const RANK_THRESHOLDS = [
  { min: 0, title: "متدرّب ميداني", badge: "🔰" },
  { min: 8, title: "مراقب سلامة", badge: "🥉" },
  { min: 18, title: "مفتش عمليات", badge: "🥈" },
  { min: 30, title: "محلل مخاطر متقدم", badge: "🥇" },
  { min: 45, title: "خبير سلامة معتمد", badge: "🏆" },
  { min: 60, title: "استشاري احترافي (CSP/IDip)", badge: "👑" },
];

function getRank(score) {
  let rank = RANK_THRESHOLDS[0];
  for (const r of RANK_THRESHOLDS) if (score >= r.min) rank = r;
  return rank;
}

const TOTAL_NODES = 67;

// ---------------------------------------------------------------------------
// أدوات مساعدة للحالة (Progress persisted in-memory only، بدون localStorage)
// ---------------------------------------------------------------------------

function useGameProgress() {
  const [completed, setCompleted] = useState({}); // { nodeId: {correct, total} }
  const [totalScore, setTotalScore] = useState(0);
  const [bonusPoints, setBonusPoints] = useState(0);

  const completedCount = Object.keys(completed).length;
  const rank = getRank(completedCount);

  const markComplete = useCallback((nodeId, correct, total, bonus = 0) => {
    setCompleted((prev) => ({ ...prev, [nodeId]: { correct, total } }));
    setTotalScore((s) => s + correct);
    if (bonus > 0) setBonusPoints((b) => b + bonus);
  }, []);

  return { completed, completedCount, totalScore, bonusPoints, rank, markComplete };
}

// ---------------------------------------------------------------------------
// مكوّن نافذة الأسئلة (QuizModal) — يطبّق مبادئ التصميم الملائم لتشتت الانتباه:
// 1) جرعات صغيرة  2) تغذية راجعة فورية متعددة الحواس  3) مكافآت متغيرة
// 4) تقدم مرئي دائم  5) تقسيم كتلي للنص  7) مؤقت اختياري غير ضاغط
// 8) وضع تركيز  9) تنويع نمط التفاعل (صح/خطأ أحياناً)
// ---------------------------------------------------------------------------

function playSfx(name) {
  if (typeof window !== "undefined" && window.SFX) {
    window.SFX.play(name);
  }
}

function QuizModal({ node, onClose, onFinish, useTrueFalseVariant }) {
  const [qIndex, setQIndex] = useState(0);
  const [selected, setSelected] = useState(null);
  const [answered, setAnswered] = useState(false);
  const [correctCount, setCorrectCount] = useState(0);
  const [showField, setShowField] = useState(false);
  const [fieldAnswer, setFieldAnswer] = useState("");
  const [elapsedMs, setElapsedMs] = useState(0);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [showBonusFlash, setShowBonusFlash] = useState(false);
  const [shakeWrong, setShakeWrong] = useState(false);
  const startTimeRef = useRef(Date.now());
  const timerRef = useRef(null);

  const question = node.questions[qIndex];
  const isLast = qIndex === node.questions.length - 1;
  const isTFQuestion = useTrueFalseVariant && qIndex === 1; // نوّع السؤال الثاني أحياناً

  // مؤقت اختياري — لا يمنع الإجابة أبداً، فقط يعرض مكافأة سرعة تحفيزية
  useEffect(() => {
    startTimeRef.current = Date.now();
    timerRef.current = setInterval(() => {
      setElapsedMs(Date.now() - startTimeRef.current);
    }, 200);
    return () => clearInterval(timerRef.current);
  }, [qIndex]);

  useEffect(() => {
    if (answered && timerRef.current) clearInterval(timerRef.current);
  }, [answered]);

  const speedBonusEligible = elapsedMs < 12000; // أقل من 12 ثانية = مؤهل لمكافأة سرعة

  // خيارات معروضة: إن كان متغير صح/خطأ، اختصر لخيارين فقط (الصحيح + خطأ عشوائي واحد)
  const displayOptions = React.useMemo(() => {
    if (!isTFQuestion) return question.options;
    const correctOpt = question.options[question.correct];
    const wrongOpts = question.options.filter((_, i) => i !== question.correct);
    const oneWrong = wrongOpts[Math.floor(Math.random() * wrongOpts.length)];
    const pair = Math.random() > 0.5 ? [correctOpt, oneWrong] : [oneWrong, correctOpt];
    return pair;
  }, [qIndex, isTFQuestion]);

  const displayCorrectIndex = isTFQuestion
    ? displayOptions.indexOf(question.options[question.correct])
    : question.correct;

  const handleSelect = (idx) => {
    if (answered) return;
    setSelected(idx);
    setAnswered(true);

    const isCorrect = idx === displayCorrectIndex;
    if (isCorrect) {
      setCorrectCount((c) => c + 1);
      playSfx("correct");

      // مكافأة متغيرة: فرصة 15% لـ"بصيرة حرجة" + مكافأة سرعة منفصلة إن وُجدت
      let bonus = 0;
      if (Math.random() < 0.15) {
        bonus += 2;
        setShowBonusFlash(true);
        setTimeout(() => setShowBonusFlash(false), 1800);
      }
      if (speedBonusEligible) bonus += 1;
      if (bonus > 0) setBonusEarned((b) => b + bonus);
    } else {
      playSfx("wrong");
      setShakeWrong(true);
      setTimeout(() => setShakeWrong(false), 420);
    }
  };

  const handleNext = () => {
    if (!isLast) {
      setQIndex((i) => i + 1);
      setSelected(null);
      setAnswered(false);
    } else {
      setShowField(true);
    }
  };

  const handleSubmitField = () => {
    playSfx("unlock");
    onFinish(node.id, correctCount, node.questions.length, bonusEarned);
  };

  const handleSkipField = () => {
    playSfx("unlock");
    onFinish(node.id, correctCount, node.questions.length, bonusEarned);
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div
        className={`modal-card ${shakeWrong ? "shake" : ""}`}
        onClick={(e) => e.stopPropagation()}
        style={{ borderColor: node.color }}
      >
        <div className="modal-head" style={{ background: node.color }}>
          <span className="modal-icon">{node.icon}</span>
          <div className="modal-head-text">
            <div className="modal-title">{node.name}</div>
            <div className="modal-subtitle">{node.subtitle}</div>
          </div>
          <button className="modal-close" onClick={onClose} aria-label="إغلاق">✕</button>
        </div>

        {showBonusFlash && (
          <div className="bonus-flash">✨ بصيرة حرجة! +2 نقطة إضافية</div>
        )}

        {!showField ? (
          <div className="modal-body">
            <div className="progress-row">
              <div className="progress-dots">
                {node.questions.map((_, i) => (
                  <span key={i} className={`dot ${i === qIndex ? "dot-active" : i < qIndex ? "dot-done" : ""}`} />
                ))}
              </div>
              {!answered && speedBonusEligible && (
                <span className="speed-hint">⚡ إجابة سريعة = نقطة إضافية</span>
              )}
            </div>

            {isTFQuestion && !answered && (
              <div className="tf-badge">تحدي سريع: صح أم خطأ؟</div>
            )}

            <p className="question-text">{question.q}</p>

            <div className={`options ${isTFQuestion ? "options-tf" : ""}`}>
              {displayOptions.map((opt, idx) => {
                let cls = "option-btn";
                if (answered) {
                  if (idx === displayCorrectIndex) cls += " option-correct";
                  else if (idx === selected) cls += " option-wrong";
                }
                return (
                  <button key={idx} className={cls} onClick={() => handleSelect(idx)} disabled={answered}>
                    {opt}
                  </button>
                );
              })}
            </div>

            {answered && (
              <div className="explain-box">
                <div className="explain-label">
                  {selected === displayCorrectIndex ? "✔ إجابة صحيحة" : "✕ إجابة غير دقيقة"}
                </div>
                <p>{question.explain}</p>
                <button className="next-btn" style={{ background: node.color }} onClick={handleNext}>
                  {isLast ? "المتابعة إلى المهمة الميدانية" : "السؤال التالي"}
                </button>
              </div>
            )}
          </div>
        ) : (
          <div className="modal-body">
            <div className="field-task-label">مهمة ميدانية تطبيقية (اختيارية)</div>
            <p className="question-text">{node.fieldTask}</p>
            <textarea
              className="field-textarea"
              rows={4}
              placeholder="اكتب إجابتك هنا بصوتك الميداني الخاص... (اختياري)"
              value={fieldAnswer}
              onChange={(e) => setFieldAnswer(e.target.value)}
            />
            <div className="field-actions">
              <button className="skip-btn" onClick={handleSkipField}>تخطّي</button>
              <button
                className="next-btn"
                style={{ background: node.color, opacity: fieldAnswer.trim().length > 5 ? 1 : 0.5 }}
                disabled={fieldAnswer.trim().length <= 5}
                onClick={handleSubmitField}
              >
                اعتماد المحطة وإغلاق التصريح
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// مكوّن خريطة المنطقة (ZoneMap) — يعرض عقد منطقة واحدة (كـID1 أو BCSP)
// نظام قفل "مرن": العقدة الأولى مفتوحة دائماً، وكل عقدة تُفتح فور إكمال
// العقدة السابقة *أو* إحدى العقدتين السابقتين لها — يمنح هذا خيارات حقيقية
// للمستخدم بدل مسار خطي جامد واحد (مبدأ "التحكم يقلل الملل" لذوي تشتت الانتباه)
// ---------------------------------------------------------------------------

function ZoneMap({ nodes, completed, onNodeClick, zoneColor }) {
  const isUnlocked = useCallback(
    (node, idx) => {
      if (idx === 0) return true;
      if (idx === 1) return !!completed[nodes[0].id];
      // من العقدة الثالثة فصاعداً: تُفتح إذا اكتملت إحدى العقدتين السابقتين مباشرة
      // (يمنح مرونة اختيار المسار بدل التتابع الجامد الصارم)
      return !!completed[nodes[idx - 1].id] || !!completed[nodes[idx - 2].id];
    },
    [completed, nodes]
  );

  return (
    <div className="zone-map">
      <svg className="path-svg">
        {nodes.map((node, idx) => {
          if (idx === 0) return null;
          const from = nodes[idx - 1];
          const done = !!completed[from.id];
          return (
            <line
              key={`${from.id}-${node.id}`}
              x1={`${from.mapX}%`}
              y1={`${from.mapY}%`}
              x2={`${node.mapX}%`}
              y2={`${node.mapY}%`}
              stroke={done ? zoneColor : "rgba(255,255,255,0.12)"}
              strokeWidth="2"
              strokeDasharray={done ? "0" : "5,5"}
            />
          );
        })}
      </svg>

      {nodes.map((node, idx) => {
        const unlocked = isUnlocked(node, idx);
        const done = !!completed[node.id];
        return (
          <div
            key={node.id}
            className={`zone-node ${unlocked ? "" : "locked"}`}
            style={{ left: `${node.mapX}%`, top: `${node.mapY}%` }}
            role="button"
            tabIndex={unlocked ? 0 : -1}
            aria-label={unlocked ? `${node.id} ${node.name}${done ? "، مكتملة" : ""}` : `${node.name}، مقفلة`}
            onClick={() => unlocked && onNodeClick(node)}
            onKeyDown={(e) => {
              if (unlocked && (e.key === "Enter" || e.key === " ")) {
                e.preventDefault();
                onNodeClick(node);
              }
            }}
          >
            <div className={`zone-node-circle ${done ? "done" : ""}`} style={{ background: unlocked ? node.color : "#333" }}>
              {node.icon}
              {!unlocked && <span className="zone-node-lock">🔒</span>}
            </div>
            <div className="zone-node-label">
              <span className="zone-node-id">{node.id}</span>
              {node.name}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ---------------------------------------------------------------------------
// توزيع مواقع العقد على الخريطة تلقائياً (نمط متعرج صناعي، وليس شبكة رتيبة)
// ---------------------------------------------------------------------------

function layoutNodes(nodes) {
  return nodes.map((node, idx) => {
    const row = Math.floor(idx / 4);
    const col = idx % 4;
    const zigzag = row % 2 === 0 ? col : 3 - col;
    const x = 12 + zigzag * 25;
    const y = 14 + row * 22;
    return { ...node, mapX: x, mapY: y };
  });
}

// ---------------------------------------------------------------------------
// لوحة PTW الحية — مؤشر التقدم البصري المميز (ضمن المنطقة الحالية المعروضة)
// ---------------------------------------------------------------------------

function PTWMeter({ zoneNodes, completed }) {
  const doneInZone = zoneNodes.filter((n) => completed[n.id]).length;
  const pct = Math.round((doneInZone / zoneNodes.length) * 100);

  return (
    <div className="ptw-card">
      <div className="ptw-head">
        <span className="ptw-code">PTW-{String(doneInZone).padStart(2, "0")}/{zoneNodes.length}</span>
        <span className="ptw-status" style={{ color: pct === 100 ? "#2e7d32" : "#c9a227" }}>
          {pct === 100 ? "معتمد بالكامل" : "قيد الاعتماد"}
        </span>
      </div>
      <div className="ptw-bar">
        <div className="ptw-bar-fill" style={{ width: `${pct}%` }} />
      </div>
      <div className="ptw-stamps">
        {zoneNodes.map((n) => (
          <div key={n.id} className={`stamp ${completed[n.id] ? "stamp-done" : ""}`} title={n.name}>
            {completed[n.id] ? "✔" : "○"}
          </div>
        ))}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// شريط التقدم الكلي الثابت (دائم الظهور — مبدأ "التقدم المرئي المستمر")
// ---------------------------------------------------------------------------

function StickyProgressBar({ completedCount, rank, bonusPoints, focusMode, onToggleFocus }) {
  const pct = Math.round((completedCount / TOTAL_NODES) * 100);
  return (
    <div className={`sticky-bar ${focusMode ? "dimmed" : ""}`}>
      <div className="sticky-rank">
        <span className="sticky-badge">{rank.badge}</span>
        <span className="sticky-title">{rank.title}</span>
      </div>
      <div className="sticky-progress">
        <div className="sticky-bar-track">
          <div className="sticky-bar-fill" style={{ width: `${pct}%` }} />
        </div>
        <span className="sticky-count">{completedCount}/{TOTAL_NODES}</span>
      </div>
      {bonusPoints > 0 && <span className="sticky-bonus">✨ {bonusPoints}</span>}
      <button className="focus-toggle" onClick={onToggleFocus} title="وضع التركيز">
        {focusMode ? "👁" : "🎯"}
      </button>
    </div>
  );
}

// ---------------------------------------------------------------------------
// شاشة اختيار المجمّع (Facility Gate) — البوابة الرئيسية للعبة
// ---------------------------------------------------------------------------

function FacilityGate({ onSelect, progress, allNodesByTrack }) {
  return (
    <div className="facility-gate">
      <div className="header">
        <div className="header-eyebrow">HASSI R'MEL · PROCESS SAFETY TRACK</div>
        <div className="header-title">رحلة المفتّش</div>
        <div className="header-sub">اختر المجمّع الذي تريد متابعة رحلتك فيه</div>
      </div>

      <div className="facility-grid">
        {Object.values(FACILITIES).map((fac) => {
          const facNodes = fac.zones.flatMap((z) => allNodesByTrack[z.key] || []);
          const doneCount = facNodes.filter((n) => progress.completed[n.id]).length;
          const pct = Math.round((doneCount / facNodes.length) * 100);
          return (
            <div
              key={fac.id}
              className="facility-card"
              role="button"
              tabIndex={0}
              aria-label={`ادخل ${fac.name}، ${pct}% مكتمل`}
              onClick={() => onSelect(fac.id)}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  onSelect(fac.id);
                }
              }}
            >
              <div className="facility-card-top">
                <span className="facility-icon">{fac.id === "nebosh" ? "🛢" : "🇺🇸"}</span>
                <div className="facility-pct">{pct}%</div>
              </div>
              <div className="facility-name">{fac.name}</div>
              <div className="facility-tagline">{fac.tagline}</div>
              <div className="facility-bar-track">
                <div className="facility-bar-fill" style={{ width: `${pct}%` }} />
              </div>
              <div className="facility-meta">{doneCount}/{facNodes.length} عقدة مكتملة · {fac.zones.length} {fac.zones.length > 1 ? "مناطق" : "منطقة"}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// المكوّن الرئيسي App
// ---------------------------------------------------------------------------

function HSEJourneyV2() {
  const progress = useGameProgress();
  const [currentFacility, setCurrentFacility] = useState(null); // null = بوابة الاختيار
  const [currentZoneIdx, setCurrentZoneIdx] = useState(0);
  const [activeNode, setActiveNode] = useState(null);
  const [toast, setToast] = useState(null);
  const [focusMode, setFocusMode] = useState(false);

  // ترتيب مواقع الخريطة لكل منطقة (تُحسب مرة واحدة)
  const laidOutData = React.useMemo(() => {
    const out = {};
    for (const key of Object.keys(GAME_DATA)) {
      out[key] = layoutNodes(GAME_DATA[key]);
    }
    return out;
  }, []);

  const facility = currentFacility ? FACILITIES[currentFacility] : null;
  const currentZone = facility ? facility.zones[currentZoneIdx] : null;
  const currentZoneNodes = currentZone ? laidOutData[currentZone.key] : [];

  // عداد تسلسلي عالمي (لتحديد كل عقدة "خامسة" لتفعيل نمط صح/خطأ التنويعي)
  const globalNodeCounter = useRef(0);

  const handleNodeClick = (node) => {
    globalNodeCounter.current += 1;
    setActiveNode(node);
  };

  const handleFinishNode = (nodeId, correct, total, bonus) => {
    progress.markComplete(nodeId, correct, total, bonus);
    setActiveNode(null);
    setToast(`تم اعتماد المحطة — ${correct}/${total} إجابات صحيحة${bonus > 0 ? ` (+${bonus} مكافأة)` : ""}`);
    setTimeout(() => setToast(null), 3200);
  };

  if (!currentFacility) {
    return (
      <div className="hse-root">
        <GameStyles />
        <FacilityGate onSelect={setCurrentFacility} progress={progress} allNodesByTrack={laidOutData} />
        <StickyProgressBar
          completedCount={progress.completedCount}
          rank={progress.rank}
          bonusPoints={progress.bonusPoints}
          focusMode={focusMode}
          onToggleFocus={() => setFocusMode((f) => !f)}
        />
      </div>
    );
  }

  const allDoneInZone = currentZoneNodes.every((n) => progress.completed[n.id]);
  const useTFVariant = globalNodeCounter.current % 5 === 0; // كل عقدة خامسة تقريباً

  return (
    <div className="hse-root">
      <GameStyles />

      <div className="zone-header">
        <button className="back-btn" onClick={() => setCurrentFacility(null)}>← المجمّعات</button>
        <div className="zone-header-text">
          <div className="header-eyebrow">{facility.tagline}</div>
          <div className="header-title-sm">{facility.name}</div>
        </div>
      </div>

      {facility.zones.length > 1 && (
        <div className="zone-tabs">
          {facility.zones.map((z, idx) => {
            const zNodes = laidOutData[z.key];
            const zDone = zNodes.filter((n) => progress.completed[n.id]).length;
            return (
              <button
                key={z.key}
                className={`zone-tab ${idx === currentZoneIdx ? "zone-tab-active" : ""}`}
                onClick={() => setCurrentZoneIdx(idx)}
              >
                <span className="zone-tab-icon">{z.icon}</span>
                <span className="zone-tab-name">{z.short}</span>
                <span className="zone-tab-count">{zDone}/{zNodes.length}</span>
              </button>
            );
          })}
        </div>
      )}

      <PTWMeter zoneNodes={currentZoneNodes} completed={progress.completed} />

      <ZoneMap
        nodes={currentZoneNodes}
        completed={progress.completed}
        onNodeClick={handleNodeClick}
        zoneColor="#c9a227"
      />

      {allDoneInZone && (
        <div className="zone-complete-banner">
          🎉 أكملت منطقة {currentZone.name} بالكامل! {facility.zones.length > 1 ? "انتقل لمنطقة أخرى أو " : ""}عد للمجمّعات لاستكشاف المزيد.
        </div>
      )}

      <StickyProgressBar
        completedCount={progress.completedCount}
        rank={progress.rank}
        bonusPoints={progress.bonusPoints}
        focusMode={focusMode}
        onToggleFocus={() => setFocusMode((f) => !f)}
      />

      {activeNode && (
        <QuizModal
          node={activeNode}
          onClose={() => setActiveNode(null)}
          onFinish={handleFinishNode}
          useTrueFalseVariant={useTFVariant}
        />
      )}

      {toast && <div className="toast">{toast}</div>}
    </div>
  );
}

